#include "kernel_operator.h"

constexpr int32_t BUFFER_NUM = 2;

class KernelCa6k00147Custom {
public:
    __aicore__ inline KernelCa6k00147Custom() {}

    __aicore__ inline void Init(GM_ADDR x, GM_ADDR y,
                                uint32_t totalLength, uint32_t tileLength,
                                float alpha) {
        totalLen_ = totalLength;
        tileLen_ = tileLength;
        alpha_ = alpha;

        xGm_.SetGlobalBuffer((__gm__ float*)x, totalLen_);
        yGm_.SetGlobalBuffer((__gm__ float*)y, totalLen_);

        pipe_.InitBuffer(inQueueX_, BUFFER_NUM, tileLen_ * sizeof(float));
        pipe_.InitBuffer(outQueueY_, BUFFER_NUM, tileLen_ * sizeof(float));
        pipe_.InitBuffer(tmpQueue1_, 1, tileLen_ * sizeof(float));
        pipe_.InitBuffer(tmpQueue2_, 1, tileLen_ * sizeof(float));
    }

    __aicore__ inline void Process() {
        if (totalLen_ == 0 || tileLen_ == 0) return;

        const uint32_t blockNum = static_cast<uint32_t>(AscendC::GetBlockNum());
        const uint32_t blockIdx = static_cast<uint32_t>(AscendC::GetBlockIdx());

        const uint32_t strideElems = blockNum * tileLen_;
        uint32_t base = blockIdx * tileLen_;
        if (base >= totalLen_) return;

        uint32_t curLen = totalLen_ - base;
        if (curLen > tileLen_) curLen = tileLen_;
        CopyIn(base, curLen);

        while (true) {
            const uint32_t nextBase = base + strideElems;
            uint32_t nextLen = 0;
            if (nextBase < totalLen_) {
                nextLen = totalLen_ - nextBase;
                if (nextLen > tileLen_) nextLen = tileLen_;
                CopyIn(nextBase, nextLen);
            }

            Compute(curLen);
            CopyOut(base, curLen);

            if (nextLen == 0) break;
            base = nextBase;
            curLen = nextLen;
        }
    }

private:
    __aicore__ inline void CopyIn(uint32_t gmOffset, uint32_t len) {
        AscendC::LocalTensor<float> xLocal = inQueueX_.AllocTensor<float>();
        AscendC::DataCopy(xLocal, xGm_[gmOffset], len);
        inQueueX_.EnQue(xLocal);
    }

    __aicore__ inline void Compute(uint32_t len) {
        AscendC::LocalTensor<float> xLocal = inQueueX_.DeQue<float>();
        AscendC::LocalTensor<float> yLocal = outQueueY_.AllocTensor<float>();
        AscendC::LocalTensor<float> t1 = tmpQueue1_.AllocTensor<float>();
        AscendC::LocalTensor<float> t2 = tmpQueue2_.AllocTensor<float>();

        // ELU: y = x if x > 0 else alpha * (exp(x) - 1)
        // Use mask-based approach:
        // mask = (x > 0) ? 1.0f : 0.0f
        // pos = x
        // neg = alpha * (Exp(x) - 1.0f)
        // y = mask * pos + (1 - mask) * neg

        // Compute pos branch = x (already in xLocal)
        // Compute neg branch = alpha * (exp(x) - 1)
        AscendC::Exp(t1, xLocal, len);                     // t1 = exp(x)
        AscendC::Sub(t1, t1, 1.0f, len);                   // t1 = exp(x) - 1
        AscendC::Muls(t1, t1, alpha_, len);                // t1 = alpha * (exp(x) - 1) = neg part

        // Create mask: (x > 0) ? 1.0f : 0.0f
        AscendC::Reciprocal(t2, xLocal, len);  // placeholder, actually use Compare
        // Use Compare: result > 0 -> 1.0f else 0.0f
        AscendC::CmpGt(t2, xLocal, 0.0f, len);            // t2 = (x > 0) ? 1.0f : 0.0f

        // y = mask * x + (1 - mask) * neg
        AscendC::Mul(t2, t2, xLocal, len);                 // t2 = mask * x
        // Now compute (1 - mask) * neg
        AscendC::Sub(t1, 1.0f, t2, len); // this is wrong; we need (1 - mask) * neg
        // Actually we need to compute maskNeg = 1 - mask, then multiply with neg
        // Let's reuse t2 and t1 properly.
        // Better approach: compute two terms separately.
        // Reset:
        AscendC::LocalTensor<float> mask = tmpQueue1_.AllocTensor<float>();
        AscendC::LocalTensor<float> neg = tmpQueue2_.AllocTensor<float>(); // reuse
        // Actually we already used t1 and t2; let's reassign.
        // To avoid confusion, we'll reallocate from scratch.
        tmpQueue1_.FreeTensor(t1);
        tmpQueue2_.FreeTensor(t2);
        // Allocate new tensors
        AscendC::LocalTensor<float> mask2 = tmpQueue1_.AllocTensor<float>();
        AscendC::LocalTensor<float> neg2 = tmpQueue2_.AllocTensor<float>();
        // Compute neg branch again (we already computed; but we released. recompute.)
        AscendC::Exp(neg2, xLocal, len);
        AscendC::Sub(neg2, neg2, 1.0f, len);
        AscendC::Muls(neg2, neg2, alpha_, len);
        // mask
        AscendC::CmpGt(mask2, xLocal, 0.0f, len);
        // y = mask * x + (1 - mask) * neg
        // Compute term1 = mask * x
        AscendC::Mul(yLocal, mask2, xLocal, len);
        // Compute (1-mask) * neg
        AscendC::Sub(mask2, 1.0f, mask2, len);  // mask2 = 1 - mask
        AscendC::Mul(neg2, mask2, neg2, len);   // neg2 = (1-mask)*neg
        AscendC::Add(yLocal, yLocal, neg2, len);

        tmpQueue1_.FreeTensor(mask2);
        tmpQueue2_.FreeTensor(neg2);
        outQueueY_.EnQue<float>(yLocal);
        inQueueX_.FreeTensor(xLocal);
    }

    __aicore__ inline void CopyOut(uint32_t gmOffset, uint32_t len) {
        AscendC::LocalTensor<float> yLocal = outQueueY_.DeQue<float>();
        AscendC::DataCopy(yGm_[gmOffset], yLocal, len);
        outQueueY_.FreeTensor(yLocal);
    }

private:
    AscendC::TPipe pipe_;
    AscendC::TQue<AscendC::TPosition::VECIN, BUFFER_NUM> inQueueX_;
    AscendC::TQue<AscendC::TPosition::VECOUT, BUFFER_NUM> outQueueY_;
    AscendC::TQue<AscendC::TPosition::VECCALC, 1> tmpQueue1_;
    AscendC::TQue<AscendC::TPosition::VECCALC, 1> tmpQueue2_;

    AscendC::GlobalTensor<float> xGm_;
    AscendC::GlobalTensor<float> yGm_;

    uint32_t totalLen_{0};
    uint32_t tileLen_{0};
    float alpha_{1.0f};
};

extern "C" __global__ __aicore__ void ca6k_00147_custom(GM_ADDR x, GM_ADDR y, GM_ADDR workspace, GM_ADDR tiling) {
    GET_TILING_DATA(tiling_data, tiling);
    KernelCa6k00147Custom op;
    op.Init(x, y, tiling_data.totalLength, tiling_data.tileLength, tiling_data.alpha);
    op.Process();
}
